const data = items[0].json;

// 🔹 Nome
const nomeUsuario = data.nome || "";

// 🔹 Contexto
const contexto = data.contexto || "";

// 🔹 Resultados
const resultados = data.resultados || [];

// 🔹 Código OTP (6 dígitos)
const codigo = data.codigo || "";

// 🔹 URL para completar cadastro
const completarCadastroUrl = data.completar_cadastro_url || "";

// 🔹 Número
const numero = data.telefone || data.numero;

// 🔹 Saudação
const saudacao = nomeUsuario ? `Oi, ${nomeUsuario}!` : "Oi!";

// 🔹 Ordenação por nota
const ordenados = [...resultados].sort(
  (a, b) => (b?.item?.nota ?? 0) - (a?.item?.nota ?? 0)
);

// 🔹 Top 2 fornecedores
const topDois = ordenados.slice(0, 2);
const totalRestante = Math.max(ordenados.length - topDois.length, 0);

// 🔹 Monta lista dos 2 primeiros
let listaFornecedores = "";
topDois.forEach((r, i) => {
  const item = r?.item || {};
  const nome = item.razao_social || "Fornecedor";
  const modelo = item.modelo_negocio ? ` — ${item.modelo_negocio}` : "";
  const site = item.site ? `\n${item.site}` : "";
  listaFornecedores += `\n\n${i + 1}. *${nome}*${modelo}${site}`;
});

// 🔹 Mensagem
let mensagem = `${saudacao} Aqui é do BuscaFornecedor.`;

if (contexto) {
  mensagem += `\n\nSeparei alguns fornecedores pra "${contexto}". Dois que se destacaram:`;
} else {
  mensagem += `\n\nSeparei alguns fornecedores pra você. Dois que se destacaram:`;
}

mensagem += listaFornecedores;

if (totalRestante > 0) {
  mensagem += `\n\nTem mais ${totalRestante} no site, com contato e detalhes completos. Dá uma olhada por lá:`;
} else {
  mensagem += `\n\nNo site você vê os contatos e detalhes completos. Dá uma olhada:`;
}

mensagem += `\n\nSeu código é *${codigo}*\n${completarCadastroUrl}\n\n(o código vale por 15 minutos)\n\nQualquer coisa, pode me chamar por aqui.`;

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

